# Example usage functions
def log_application_event(message, level='info'):
    """Log application events"""
    logger = get_logger(__name__)
    getattr(logger, level.lower())(message)

def log_error(message, exc_info=None):
    """Log error with exception information"""
    logger = get_logger(__name__)
    logger.error(message, exc_info=exc_info)

def log_access(client_ip, method, path, status_code, response_time):
    """Log HTTP access"""
    access_logger = get_access_logger()
    access_logger.info(f'{client_ip} - {method} {path} - {status_code} - {response_time}ms')